import { describe, expect, it } from 'vitest';
import { ServerError } from '@/shared/lib/errorHandling/errors';
import { parseTaskCreationResponse } from './parseTaskCreationResponse';

const context = {
  requestId: 'req-1',
  taskType: 'image',
  projectId: 'proj-1',
};

describe('parseTaskCreationResponse', () => {
  it('parses valid payloads and trims task ids', () => {
    const result = parseTaskCreationResponse(
      { task_id: '  task-123  ', status: 'queued' },
      context,
    );

    expect(result).toEqual({
      task_id: 'task-123',
      status: 'queued',
    });
  });

  it('defaults status to pending when status is missing or empty', () => {
    const result = parseTaskCreationResponse(
      { task_id: 'task-456', status: '   ' },
      context,
    );

    expect(result).toEqual({
      task_id: 'task-456',
      status: 'pending',
    });
  });

  it('throws ServerError for non-record payloads', () => {
    expect(() => parseTaskCreationResponse(null, context)).toThrow(ServerError);
    expect(() => parseTaskCreationResponse([], context)).toThrow(ServerError);
  });

  it('throws ServerError with inline message when task id is absent', () => {
    expect(() =>
      parseTaskCreationResponse(
        { error: ' Task queue unavailable ', status: 'failed' },
        context,
      ),
    ).toThrow('Task queue unavailable');
  });
});

/**
 * useTaskPlaceholder — Collapse placeholder lifecycle to one call.
 *
 * Every task-creation callsite needs the same 5-step ceremony:
 *   addIncomingTask → create → resolveTaskIds → refetch → removeIncomingTask
 * This hook wraps that into a single `run()` function.
 *
 * Also handles mid-flight cancellation: if cancelAllIncoming() is called
 * while create() is in flight, the newly created tasks are cancelled in DB.
 */

import { useCallback } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { requireSession } from '@/integrations/supabase/auth/ensureAuthenticatedSession';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { invokeSupabaseEdgeFunction } from '@/integrations/supabase/functions/invokeSupabaseEdgeFunction';
import { useIncomingTasks } from '@/shared/contexts/IncomingTasksContext';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { taskQueryKeys } from '@/shared/lib/queryKeys/tasks';

interface TaskPlaceholderOptions {
  taskType: string;
  label: string;
  expectedCount?: number;
  context: string;
  toastTitle: string;
  create: () => Promise<unknown>;
  /** Extra work after task IDs are resolved (e.g. invalidateQueries). */
  onSuccess?: (taskIds: string[]) => void | Promise<void>;
}

/**
 * Extract task IDs from whatever shape the create() function returns.
 *
 * Handles:
 *  - string                        → raw task_id
 *  - string[]                      → array of raw task_ids
 *  - { task_id: string }           → single TaskCreationResult
 *  - Array<{ task_id: string }>    → batch results
 *  - mixed arrays of strings and objects
 *  - void/null/undefined           → [] (graceful degradation)
 */
export function extractTaskIds(result: unknown): string[] {
  if (result == null) return [];

  if (typeof result === 'string') return [result];

  if (Array.isArray(result)) {
    return result.flatMap(item => {
      if (typeof item === 'string') return [item];
      if (item != null && typeof item === 'object' && 'task_id' in item) {
        const id = (item as { task_id: unknown }).task_id;
        if (typeof id === 'string') return [id];
      }
      return [];
    });
  }

  if (typeof result === 'object' && 'task_id' in result) {
    const id = (result as { task_id: unknown }).task_id;
    if (typeof id === 'string') return [id];
  }

  return [];
}

/** Cancel specific task IDs through the audited task-status edge path. */
async function cancelTasksByIds(taskIds: string[]): Promise<void> {
  if (taskIds.length === 0) return;

  const session = await requireSession(supabase(), 'useTaskPlaceholder.cancelTasksByIds');
  const results = await Promise.allSettled(taskIds.map((taskId) => (
    invokeSupabaseEdgeFunction('update-task-status', {
      body: {
        task_id: taskId,
        status: 'Cancelled',
      },
      headers: {
        Authorization: `Bearer ${session.access_token}`,
      },
      timeoutMs: 20000,
    })
  )));

  const rejected = results.find(
    (result): result is PromiseRejectedResult => result.status === 'rejected',
  );
  if (rejected) {
    normalizeAndPresentError(rejected.reason, {
      context: 'useTaskPlaceholder.cancelTasksByIds',
      showToast: false,
    });
  }
}

export type RunTaskPlaceholder = (options: TaskPlaceholderOptions) => Promise<void>;

/**
 * Returns a stable `run` function that wraps the full placeholder lifecycle.
 *
 * Usage:
 * ```ts
 * const run = useTaskPlaceholder();
 * await run({
 *   taskType: 'image-upscale', label: 'Upscale 2x',
 *   context: 'useUpscale', toastTitle: 'Upscale failed',
 *   create: () => createImageUpscaleTask(params),
 * });
 * ```
 */
export function useTaskPlaceholder(): RunTaskPlaceholder {
  const { addIncomingTask, removeIncomingTask, resolveTaskIds, wasCancelled, acknowledgeCancellation } = useIncomingTasks();
  const queryClient = useQueryClient();

  return useCallback(async (options: TaskPlaceholderOptions) => {
    const incomingTaskId = addIncomingTask({
      taskType: options.taskType,
      label: options.label,
      expectedCount: options.expectedCount,
    });

    try {
      const result = await options.create();
      const taskIds = extractTaskIds(result);

      // If cancelled while create() was in flight, cancel the newly created tasks.
      if (wasCancelled(incomingTaskId)) {
        if (taskIds.length > 0) {
          await cancelTasksByIds(taskIds);
        }
        acknowledgeCancellation(incomingTaskId);
        return; // finally block still runs for refetch + cleanup
      }

      if (taskIds.length > 0) {
        resolveTaskIds(incomingTaskId, taskIds);
      }

      await options.onSuccess?.(taskIds);
    } catch (error) {
      if (wasCancelled(incomingTaskId)) {
        acknowledgeCancellation(incomingTaskId);
        return; // Swallow errors from cancelled tasks
      }
      normalizeAndPresentError(error, { context: options.context, toastTitle: options.toastTitle });
    } finally {
      await queryClient.refetchQueries({ queryKey: taskQueryKeys.paginatedAll });
      await queryClient.refetchQueries({ queryKey: taskQueryKeys.statusCountsAll });
      // Safe even if already removed by cancelAllIncoming — filter is a no-op
      removeIncomingTask(incomingTaskId);
    }
  }, [addIncomingTask, removeIncomingTask, resolveTaskIds, queryClient, wasCancelled, acknowledgeCancellation]);
}

interface ParsedCreateTaskBody {
  task_id?: string;
  params: Record<string, unknown>;
  task_type: string;
  project_id?: string;
  normalizedDependantOn: string[] | null;
  idempotency_key?: string;
}

interface TaskInsertObject {
  id?: string;
  params: Record<string, unknown>;
  task_type: string;
  project_id: string;
  dependant_on: string[] | null;
  status: 'Queued';
  created_at: string;
  idempotency_key?: string;
}

interface ParseSuccess {
  ok: true;
  value: ParsedCreateTaskBody;
}

interface ParseFailure {
  ok: false;
  error: string;
}

type ParseResult = ParseSuccess | ParseFailure;
type DependantOnParseResult = { ok: true; value: string[] | null } | ParseFailure;

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

function asNonEmptyString(value: unknown): string | null {
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
}

export function normalizeDependantOn(value: unknown): string[] | null {
  if (Array.isArray(value)) {
    return value.map((entry) => asNonEmptyString(entry)).filter((entry): entry is string => entry !== null);
  }

  const one = asNonEmptyString(value);
  return one ? [one] : null;
}

function parseDependantOn(value: unknown): DependantOnParseResult {
  if (value === undefined || value === null) {
    return { ok: true, value: null };
  }

  if (Array.isArray(value)) {
    if (value.length === 0) {
      return {
        ok: false,
        error: 'dependant_on must be a non-empty string or array of non-empty strings when provided',
      };
    }

    const normalized = normalizeDependantOn(value);
    if (normalized.length !== value.length) {
      return {
        ok: false,
        error: 'dependant_on must be a non-empty string or array of non-empty strings when provided',
      };
    }

    return { ok: true, value: normalized };
  }

  const one = asNonEmptyString(value);
  if (!one) {
    return {
      ok: false,
      error: 'dependant_on must be a non-empty string or array of non-empty strings when provided',
    };
  }

  return { ok: true, value: [one] };
}

export function parseCreateTaskBody(body: unknown): ParseResult {
  if (!isRecord(body)) {
    return { ok: false, error: 'Invalid JSON body' };
  }

  const params = body.params;
  const taskType = asNonEmptyString(body.task_type);

  if (!isRecord(params) || !taskType) {
    return { ok: false, error: 'params, task_type required' };
  }

  const taskId = body.task_id === undefined ? undefined : asNonEmptyString(body.task_id);
  if (body.task_id !== undefined && taskId === null) {
    return { ok: false, error: 'task_id must be a non-empty string when provided' };
  }

  const projectId = body.project_id === undefined ? undefined : asNonEmptyString(body.project_id);
  if (body.project_id !== undefined && projectId === null) {
    return { ok: false, error: 'project_id must be a non-empty string when provided' };
  }

  const idempotencyKey = body.idempotency_key === undefined
    ? undefined
    : asNonEmptyString(body.idempotency_key);
  if (body.idempotency_key !== undefined && idempotencyKey === null) {
    return { ok: false, error: 'idempotency_key must be a non-empty string when provided' };
  }

  const dependantOn = parseDependantOn(body.dependant_on);
  if (!dependantOn.ok) {
    return dependantOn;
  }

  return {
    ok: true,
    value: {
      task_id: taskId,
      params,
      task_type: taskType,
      project_id: projectId,
      normalizedDependantOn: dependantOn.value,
      idempotency_key: idempotencyKey,
    },
  };
}

interface BuildTaskInsertObjectParams {
  request: ParsedCreateTaskBody;
  finalProjectId: string;
  now?: Date;
}

export function buildTaskInsertObject({
  request,
  finalProjectId,
  now = new Date(),
}: BuildTaskInsertObjectParams): TaskInsertObject {
  const insertObject: TaskInsertObject = {
    params: request.params,
    task_type: request.task_type,
    project_id: finalProjectId,
    dependant_on: request.normalizedDependantOn,
    status: 'Queued',
    created_at: now.toISOString(),
  };

  if (request.task_id) {
    insertObject.id = request.task_id;
  }

  if (request.idempotency_key) {
    insertObject.idempotency_key = request.idempotency_key;
  }

  return insertObject;
}

export function getErrorMessage(error: unknown): string {
  if (error instanceof Error && error.message) return error.message;
  if (typeof error === 'string' && error.length > 0) return error;
  return 'Unknown error';
}

import { ServerError } from '@/shared/lib/errorHandling/errors';
import type { TaskCreationResult } from './types';

interface TaskCreationContext {
  requestId: string;
  taskType: string;
  projectId: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

export function parseTaskCreationResponse(
  payload: unknown,
  context: TaskCreationContext,
): TaskCreationResult {
  if (!isRecord(payload)) {
    throw new ServerError('Task creation returned an invalid response', {
      context,
    });
  }

  const taskId = typeof payload.task_id === 'string' ? payload.task_id.trim() : '';
  if (!taskId) {
    const inlineError = typeof payload.error === 'string' ? payload.error.trim() : '';
    throw new ServerError(inlineError || 'Task creation failed before returning a task id', {
      context: {
        ...context,
        responseStatus: typeof payload.status === 'string' ? payload.status : 'unknown',
      },
    });
  }

  const status = typeof payload.status === 'string' && payload.status.trim().length > 0
    ? payload.status
    : 'pending';

  return {
    task_id: taskId,
    status,
  };
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { extractTaskIds, useTaskPlaceholder } from '../useTaskPlaceholder';

// ---------------------------------------------------------------------------
// extractTaskIds – pure utility, no mocks needed
// ---------------------------------------------------------------------------

describe('extractTaskIds', () => {
  it('returns [] for null/undefined/void', () => {
    expect(extractTaskIds(null)).toEqual([]);
    expect(extractTaskIds(undefined)).toEqual([]);
  });

  it('wraps a single string', () => {
    expect(extractTaskIds('abc-123')).toEqual(['abc-123']);
  });

  it('extracts { task_id } from a single object', () => {
    expect(extractTaskIds({ task_id: 'task-1' })).toEqual(['task-1']);
  });

  it('extracts task_ids from an array of objects', () => {
    const batch = [
      { task_id: 'a' },
      { task_id: 'b' },
      { task_id: 'c' },
    ];
    expect(extractTaskIds(batch)).toEqual(['a', 'b', 'c']);
  });

  it('filters out array items without task_id', () => {
    const mixed = [
      { task_id: 'ok' },
      { other: 'no' },
      null,
      { task_id: 'also-ok' },
    ];
    expect(extractTaskIds(mixed)).toEqual(['ok', 'also-ok']);
  });

  it('extracts IDs from a plain string array', () => {
    expect(extractTaskIds(['id-1', 'id-2', 'id-3'])).toEqual(['id-1', 'id-2', 'id-3']);
  });

  it('handles mixed string and object arrays', () => {
    const mixed = ['id-1', { task_id: 'id-2' }, null, 'id-3'];
    expect(extractTaskIds(mixed)).toEqual(['id-1', 'id-2', 'id-3']);
  });

  it('returns [] for unrecognized shapes', () => {
    expect(extractTaskIds(42)).toEqual([]);
    expect(extractTaskIds({ id: 'not-task-id' })).toEqual([]);
    expect(extractTaskIds(true)).toEqual([]);
  });

  it('returns [] for empty array', () => {
    expect(extractTaskIds([])).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// useTaskPlaceholder – integration test with mocked context
// ---------------------------------------------------------------------------

const mockAddIncomingTask = vi.fn(() => 'incoming-1');
const mockRemoveIncomingTask = vi.fn();
const mockResolveTaskIds = vi.fn();
const mockWasCancelled = vi.fn(() => false);
const mockAcknowledgeCancellation = vi.fn();
const mockRefetchQueries = vi.fn(() => Promise.resolve());

vi.mock('@/shared/contexts/IncomingTasksContext', () => ({
  useIncomingTasks: () => ({
    addIncomingTask: mockAddIncomingTask,
    removeIncomingTask: mockRemoveIncomingTask,
    resolveTaskIds: mockResolveTaskIds,
    wasCancelled: mockWasCancelled,
    acknowledgeCancellation: mockAcknowledgeCancellation,
    cancelIncoming: vi.fn(),
    cancelAllIncoming: vi.fn(),
  }),
}));

vi.mock('@tanstack/react-query', () => ({
  useQueryClient: () => ({
    refetchQueries: mockRefetchQueries,
  }),
}));

const mockInvokeWithTimeout = vi.fn();
const mockRequireSession = vi.fn().mockResolvedValue({
  access_token: 'session-token',
  user: { id: 'user-1' },
});

vi.mock('@/integrations/supabase/client', () => ({
  getSupabaseClient: () => ({}),
}));

vi.mock('@/integrations/supabase/auth/ensureAuthenticatedSession', () => ({
  requireSession: (...args: unknown[]) => mockRequireSession(...args),
}));

vi.mock('@/integrations/supabase/functions/invokeSupabaseEdgeFunction', () => ({
  invokeSupabaseEdgeFunction: (...args: unknown[]) => mockInvokeWithTimeout(...args),
}));

vi.mock('@/shared/lib/errorHandling/runtimeError', () => ({
  normalizeAndPresentError: vi.fn(),
}));

describe('useTaskPlaceholder', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    mockRequireSession.mockResolvedValue({
      access_token: 'session-token',
      user: { id: 'user-1' },
    });
    mockInvokeWithTimeout.mockResolvedValue({});
  });

  it('runs full lifecycle on success', async () => {
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'image-upscale',
        label: 'Upscale 2x',
        context: 'test',
        toastTitle: 'Failed',
        create: async () => ({ task_id: 'real-task-1' }),
      });
    });

    // 1. addIncomingTask called
    expect(mockAddIncomingTask).toHaveBeenCalledWith({
      taskType: 'image-upscale',
      label: 'Upscale 2x',
      expectedCount: undefined,
    });

    // 2. resolveTaskIds called with extracted ID
    expect(mockResolveTaskIds).toHaveBeenCalledWith('incoming-1', ['real-task-1']);

    // 3. refetch called in finally
    expect(mockRefetchQueries).toHaveBeenCalledTimes(2);

    // 4. removeIncomingTask called in finally
    expect(mockRemoveIncomingTask).toHaveBeenCalledWith('incoming-1');
  });

  it('still cleans up on error', async () => {
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'image-upscale',
        label: 'Upscale 2x',
        context: 'test',
        toastTitle: 'Failed',
        create: async () => {
          throw new Error('boom');
        },
      });
    });

    // resolveTaskIds should NOT be called
    expect(mockResolveTaskIds).not.toHaveBeenCalled();

    // cleanup still happens
    expect(mockRefetchQueries).toHaveBeenCalledTimes(2);
    expect(mockRemoveIncomingTask).toHaveBeenCalledWith('incoming-1');
  });

  it('calls onSuccess with extracted task IDs', async () => {
    const onSuccess = vi.fn();
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'test',
        label: 'test',
        context: 'test',
        toastTitle: 'Failed',
        create: async () => [{ task_id: 'a' }, { task_id: 'b' }],
        onSuccess,
      });
    });

    expect(onSuccess).toHaveBeenCalledWith(['a', 'b']);
    expect(mockResolveTaskIds).toHaveBeenCalledWith('incoming-1', ['a', 'b']);
  });

  it('skips resolveTaskIds when create returns void', async () => {
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'test',
        label: 'test',
        context: 'test',
        toastTitle: 'Failed',
        create: async () => undefined,
      });
    });

    expect(mockResolveTaskIds).not.toHaveBeenCalled();
    expect(mockRemoveIncomingTask).toHaveBeenCalledWith('incoming-1');
  });

  it('passes expectedCount through to addIncomingTask', async () => {
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'image_generation',
        label: 'Generate 4 images',
        expectedCount: 4,
        context: 'test',

        context: 'test',
        toastTitle: 'Failed',
        create: async () => null,
      });
    });

    expect(mockAddIncomingTask).toHaveBeenCalledWith({
      taskType: 'image_generation',
      label: 'Generate 4 images',
      expectedCount: 4,
    });
  });

  it('cancels newly created tasks through the audited edge status path when the placeholder was cancelled mid-flight', async () => {
    mockWasCancelled.mockReturnValue(true);
    const { result } = renderHook(() => useTaskPlaceholder());

    await act(async () => {
      await result.current({
        taskType: 'image_generation',
        label: 'Generate 1 image',
        context: 'test',
        toastTitle: 'Failed',
        create: async () => ({ task_id: 'task-1' }),
      });
    });

    expect(mockRequireSession).toHaveBeenCalled();
    expect(mockInvokeWithTimeout).toHaveBeenCalledWith('update-task-status', expect.objectContaining({
      body: { task_id: 'task-1', status: 'Cancelled' },
      headers: { Authorization: 'Bearer session-token' },
    }));
    expect(mockResolveTaskIds).not.toHaveBeenCalled();
    expect(mockAcknowledgeCancellation).toHaveBeenCalledWith('incoming-1');
  });
});

