export function generateUUID(): string {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  // Fallback for insecure contexts (HTTP on mobile)
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });
}

export function generateTaskId(taskTypePrefix: string): string {
  const runId = generateRunId();
  const shortUuid = generateUUID().slice(0, 6);
  return `${taskTypePrefix}_${runId.substring(2, 10)}_${shortUuid}`;
}

export function generateRunId(): string {
  return new Date().toISOString().replace(/[-:.TZ]/g, '');
}

type PayloadRecord = Record<string, unknown>;

interface TaskLineageFields {
  shotId?: string;
  basedOn?: string;
  sourceVariantId?: string;
  createAsGeneration?: boolean;
  toolType?: string;
  markPrimaryWhenBasedOn?: boolean;
}

export function setTaskLineageFields(
  payload: PayloadRecord,
  fields: TaskLineageFields,
): void {
  if (fields.shotId) payload['shot_id'] = fields.shotId;
  if (fields.basedOn) {
    payload['based_on'] = fields.basedOn;
    // Keep both lineage keys for compatibility across workers that read either field.
    payload['parent_generation_id'] = fields.basedOn;
  }
  if (fields.sourceVariantId) payload['source_variant_id'] = fields.sourceVariantId;
  if (fields.createAsGeneration) payload['create_as_generation'] = true;
  if (fields.toolType) payload['tool_type'] = fields.toolType;
  if (fields.markPrimaryWhenBasedOn && fields.basedOn) payload['is_primary'] = true;
}

// A map of common aspect ratios to specific pixel resolutions.
// This ensures that generated media conforms to a set of standard dimensions.
export const ASPECT_RATIO_TO_RESOLUTION: { [key: string]: string } = {
  '21:9': '1024x438',
  '16:9': '902x508',
  '4:3': '768x576',
  '3:2': '768x512',
  '1:1': '670x670',
  '2:3': '512x768',
  '3:4': '576x768',
  '9:16': '508x902',
  '9:21': '438x1024',
  // Legacy support for 'Square' key for backwards compatibility
  'Square': '670x670',
};

// LTX models produce significantly better results at higher resolutions.
// Community consensus: 1080p minimum for good quality, 720p absolute minimum.
// These are ~2x the base resolutions, targeting ~720p–1080p range.
export const LTX_ASPECT_RATIO_TO_RESOLUTION: { [key: string]: string } = {
  '21:9': '1792x768',
  '16:9': '1280x720',
  '4:3': '1024x768',
  '3:2': '1152x768',
  '1:1': '1024x1024',
  '2:3': '768x1152',
  '3:4': '768x1024',
  '9:16': '720x1280',
  '9:21': '768x1792',
  'Square': '1024x1024',
};

/**
 * Parses a "W:H" string into a numerical ratio (W / H).
 * @param ratioStr The aspect ratio string (e.g., "16:9").
 * @returns The numerical ratio, or NaN if the format is invalid.
 */
export const parseRatio = (ratioStr: string | undefined | null): number => {
  if (!ratioStr) return NaN;
  if (ratioStr === 'Square') return 1;
  const parts = ratioStr.split(':');
  if (parts.length === 2) {
    const w = parseInt(parts[0], 10);
    const h = parseInt(parts[1], 10);
    if (!isNaN(w) && !isNaN(h) && h !== 0) {
      return w / h;
    }
  }
  return NaN;
};

/**
 * Finds the closest predefined aspect ratio string from ASPECT_RATIO_TO_RESOLUTION.
 * @param targetRatio The numerical aspect ratio to match (width / height).
 * @returns The closest matching aspect ratio string (e.g., "16:9").
 */
export function findClosestAspectRatio(targetRatio: number): string {
  const ratioKeys = Object.keys(ASPECT_RATIO_TO_RESOLUTION);
  if (ratioKeys.length === 0) {
    return '1:1'; // Fallback
  }

  let closestRatioKey: string = ratioKeys[0];
  let minDiff = Infinity;

  for (const ratioStr of ratioKeys) {
    const predefinedRatioValue = parseRatio(ratioStr);
    if (isNaN(predefinedRatioValue)) continue;

    const diff = Math.abs(targetRatio - predefinedRatioValue);
    if (diff < minDiff) {
      minDiff = diff;
      closestRatioKey = ratioStr;
    }
  }

  return closestRatioKey;
}

/**
 * Get preview dimensions constrained to a max height, maintaining aspect ratio.
 * Used for video scrubbing previews and similar floating popups.
 * @param aspectRatioStr The aspect ratio string (e.g., "16:9"). Falls back to 16:9 if invalid.
 * @param maxHeight Maximum height in pixels (default: 200)
 */
export function getPreviewDimensions(
  aspectRatioStr: string | undefined | null,
  maxHeight: number = 200
): { width: number; height: number } {
  const defaultDims = { width: Math.round(maxHeight * 16 / 9), height: maxHeight };
  if (!aspectRatioStr) return defaultDims;
  const [w, h] = aspectRatioStr.split(':').map(Number);
  if (w && h) {
    return { width: Math.round(maxHeight * (w / h)), height: maxHeight };
  }
  return defaultDims;
}

import { TaskValidationError } from './types';
import type { PathLoraConfig } from '@/domains/lora/types/lora';

interface NumericRangeOptions {
  field: string;
  label: string;
  min: number;
  max: number;
}

interface LoraValidationOptions<
  T extends Record<string, unknown>,
  TPathField extends keyof T,
  TStrengthField extends keyof T,
> {
  pathField: TPathField;
  strengthField: TStrengthField;
  strengthLabel: string;
  min: number;
  max: number;
}

interface ResolveSeed32BitOptions {
  seed?: number;
  randomize?: boolean;
  fallbackSeed?: number;
  field?: string;
}

const MAX_SEED_32_BIT = 0x7fffffff;

export function validateNonEmptyString(
  value: string,
  field: string,
  label: string,
): void {
  if (value.trim() === '') {
    throw new TaskValidationError(`${label} cannot be empty`, field);
  }
}

export function validateUrlString(
  value: string,
  field: string,
  label: string,
): void {
  try {
    new URL(value);
  } catch {
    throw new TaskValidationError(`${label} must be a valid URL`, field);
  }
}

export function validateNumericRange(
  value: number | undefined,
  { field, label, min, max }: NumericRangeOptions,
): void {
  if (value === undefined) {
    return;
  }
  if (value < min || value > max) {
    throw new TaskValidationError(`${label} must be between ${min} and ${max}`, field);
  }
}

export function validateSeed32Bit(seed: number | undefined, field = 'seed'): void {
  validateNumericRange(seed, {
    field,
    label: 'Seed',
    min: 0,
    max: MAX_SEED_32_BIT,
  });
}

function generateSeed32Bit(): number {
  return Math.floor(Math.random() * MAX_SEED_32_BIT);
}

export function resolveSeed32Bit({
  seed,
  randomize = false,
  fallbackSeed,
  field = 'seed',
}: ResolveSeed32BitOptions): number {
  if (randomize) {
    return generateSeed32Bit();
  }

  const resolvedSeed = seed ?? fallbackSeed;
  if (resolvedSeed !== undefined) {
    validateSeed32Bit(resolvedSeed, field);
    return resolvedSeed;
  }

  return generateSeed32Bit();
}

export function validateLoraConfigs<
  T extends Record<string, unknown>,
  TPathField extends keyof T,
  TStrengthField extends keyof T,
>(
  loras: T[] | undefined,
  options: LoraValidationOptions<T, TPathField, TStrengthField>,
): void {
  if (!loras?.length) {
    return;
  }

  const {
    pathField,
    strengthField,
    strengthLabel,
    min,
    max,
  } = options;

  loras.forEach((lora, index) => {
    const pathValue = lora[pathField];
    if (typeof pathValue !== 'string' || pathValue.trim() === '') {
      throw new TaskValidationError(`LoRA ${index + 1}: path is required`, `loras[${index}].${String(pathField)}`);
    }

    const strengthValue = lora[strengthField];
    if (typeof strengthValue !== 'number') {
      throw new TaskValidationError(`LoRA ${index + 1}: ${strengthLabel} is required`, `loras[${index}].${String(strengthField)}`);
    }
    if (strengthValue < min || strengthValue > max) {
      throw new TaskValidationError(
        `LoRA ${index + 1}: ${strengthLabel} must be between ${min} and ${max}`,
        `loras[${index}].${String(strengthField)}`,
      );
    }
  });
}

export function mapPathLorasToStrengthRecord(
  loras: PathLoraConfig[] | undefined,
): Record<string, number> {
  if (!loras?.length) {
    return {};
  }

  return loras.reduce<Record<string, number>>((acc, lora) => {
    if (lora.path) {
      acc[lora.path] = lora.strength;
    }
    return acc;
  }, {});
}

import type { HiresFixApiParams } from './types';

/**
 * Builds a flat params record from HiresFixApiParams.
 * Only includes fields that are defined, so the result can be spread into task params.
 */
export function buildHiresFixParams(hiresFix: HiresFixApiParams | undefined): Record<string, unknown> {
  if (!hiresFix) return {};

  const params: Record<string, unknown> = {};

  if (hiresFix.num_inference_steps !== undefined) params.num_inference_steps = hiresFix.num_inference_steps;
  if (hiresFix.hires_scale !== undefined) params.hires_scale = hiresFix.hires_scale;
  if (hiresFix.hires_steps !== undefined) params.hires_steps = hiresFix.hires_steps;
  if (hiresFix.hires_denoise !== undefined) params.hires_denoise = hiresFix.hires_denoise;
  if (hiresFix.lightning_lora_strength_phase_1 !== undefined) params.lightning_lora_strength_phase_1 = hiresFix.lightning_lora_strength_phase_1;
  if (hiresFix.lightning_lora_strength_phase_2 !== undefined) params.lightning_lora_strength_phase_2 = hiresFix.lightning_lora_strength_phase_2;
  if (hiresFix.additional_loras && Object.keys(hiresFix.additional_loras).length > 0) params.additional_loras = hiresFix.additional_loras;

  return params;
}

