export function buildIndividualTravelSegmentParams(
  params: IndividualTravelSegmentParams,
  finalResolution: string,
): Record<string, unknown> {
  const state = buildSegmentState(params);
  const orchestratorDetails = buildOrchestratorDetails(params, state, finalResolution);
  const sourceSnapshot = buildTaskPayloadSnapshot(params.originalParams);
  const legacyContractTaskId = extractOrchestratorTaskIdParam(params.originalParams);
  const legacyRunId = extractRunIdParam(params.originalParams);
  const orchestratorTaskId = resolveSnapshotOrchestratorTaskId(sourceSnapshot)
    ?? legacyContractTaskId
    ?? resolveStringCandidate(
      asString(state.orchDetails.orchestrator_task_id),
      asString(state.orig.orchestrator_task_id_ref),
    );
  const runId = resolveSnapshotRunId(sourceSnapshot)
    ?? legacyRunId
    ?? asString(state.orchDetails.run_id);

  const hasPairShotGenerationId = Boolean(
    params.pair_shot_generation_id
    || params.start_image_variant_id
    || params.end_image_variant_id,
  );
  const segmentRegenerationMode = hasPairShotGenerationId
    ? 'segment_regen_from_pair'
    : 'segment_regen_from_order';
  const generationRouting = params.child_generation_id
    ? 'variant_child'
    : 'child_generation';

  const familyContract = buildIndividualSegmentFamilyContract({
    segmentRegenerationMode,
    generationRouting,
    segmentIndex: params.segment_index,
    hasEndImage: Boolean(params.end_image_url),
    hasPairShotGenerationId,
  });

  const composedPayload = composeTaskFamilyPayload({
    taskFamily: 'individual_travel_segment',
    orchestratorDetails,
    orchestrationInput: {
      taskFamily: 'individual_travel_segment',
      orchestratorTaskId,
      runId,
      parentGenerationId: params.parent_generation_id,
      childGenerationId: params.child_generation_id,
      childOrder: params.segment_index,
      shotId: params.shot_id,
      generationRouting,
      siblingLookup: runId ? 'run_id' : 'orchestrator_task_id',
      segmentRegenerationMode,
    },
    taskViewInput: {
      inputImages: state.inputImages,
      prompt: state.basePrompt,
      enhancedPrompt: state.enhancedPrompt,
      negativePrompt: state.negativePrompt,
      modelName: state.modelName,
      resolution: finalResolution,
    },
    familyContract,
  });

  const taskParams = {
    ...buildTaskParamsPayload(params, state, finalResolution, orchestratorDetails),
    ...composedPayload,
  };
  taskParams.individual_segment_params = buildIndividualSegmentParamsPayload(params, state);
  return taskParams;
}

import { useState, useCallback, useRef } from 'react';
import { GenerationRow } from '@/domains/generation/types';
import { createImageUpscaleTask } from '@/shared/lib/tasks/families/imageUpscale';
import { getGenerationId, getMediaUrl } from '@/shared/lib/media/mediaTypeHelpers';
import type { ImageUpscaleSettings } from '../components/ImageUpscaleForm';
import { useTaskPlaceholder } from '@/shared/hooks/tasks/useTaskPlaceholder';

interface UseUpscaleProps {
  media: GenerationRow | undefined;
  selectedProjectId: string | null;
  isVideo: boolean;
  shotId?: string;
}

interface UseUpscaleReturn {
  isUpscaling: boolean;
  upscaleSuccess: boolean;
  handleUpscale: (settings: ImageUpscaleSettings) => Promise<void>;
  /** Update the active variant info so handleUpscale uses the correct image.
   *  Call this after variant data becomes available (e.g. from useSharedLightboxState). */
  setActiveVariant: (location: string | null | undefined, id: string | null | undefined) => void;
  effectiveImageUrl: string;
}

/**
 * Hook for managing image upscaling functionality
 *
 * Simple pattern matching other edit tasks (inpaint, etc.):
 * 1. Click button → isUpscaling = true
 * 2. Task created → upscaleSuccess = true briefly
 * 3. Reset after timeout
 *
 * Variant tracking: call setActiveVariant() after variant data is available
 * so handleUpscale upscales the currently-viewed variant (not the base generation).
 */
export const useUpscale = ({
  media,
  selectedProjectId,
  isVideo,
  shotId,
}: UseUpscaleProps): UseUpscaleReturn => {
  const [isUpscaling, setIsUpscaling] = useState(false);
  const [upscaleSuccess, setUpscaleSuccess] = useState(false);
  const run = useTaskPlaceholder();

  // Get media URL
  const mediaUrl = media ? (getMediaUrl(media) || media.imageUrl || '') : '';

  // Refs for active variant info — set via setActiveVariant after variant data loads.
  // Using refs so the handleUpscale callback always reads the latest values
  // without needing them in useCallback deps (avoids hook-ordering issues).
  const activeVariantLocationRef = useRef<string | null | undefined>(null);
  const activeVariantIdRef = useRef<string | null | undefined>(null);

  const setActiveVariant = useCallback((location: string | null | undefined, id: string | null | undefined) => {
    activeVariantLocationRef.current = location;
    activeVariantIdRef.current = id;
  }, []);

  const handleUpscale = useCallback(async (settings: ImageUpscaleSettings) => {
    if (!media || !selectedProjectId || isVideo) {
      return;
    }

    // Use active variant's location if viewing a variant, otherwise use base generation URL
    const activeVariantLocation = activeVariantLocationRef.current;
    const activeVariantId = activeVariantIdRef.current;
    const effectiveImageUrl = activeVariantLocation || mediaUrl;

    setIsUpscaling(true);
    try {
      await run({
        taskType: 'image-upscale',
        label: `Upscale ${settings.scaleFactor}x`,
        context: 'useUpscale',
        toastTitle: 'Failed to create enhance task',
        create: async () => {
          if (!effectiveImageUrl) {
            throw new Error('No image URL available');
          }

          const actualGenerationId = getGenerationId(media);

          return createImageUpscaleTask({
            project_id: selectedProjectId,
            image_url: effectiveImageUrl,
            generation_id: actualGenerationId,
            source_variant_id: activeVariantId || undefined,
            scale_factor: settings.scaleFactor,
            noise_scale: settings.noiseScale,
            shot_id: shotId,
          });
        },
        onSuccess: () => {
          // Show success state briefly
          setUpscaleSuccess(true);
          setTimeout(() => {
            setUpscaleSuccess(false);
          }, 2000);
        },
      });
    } finally {
      setIsUpscaling(false);
    }
  }, [media, selectedProjectId, isVideo, mediaUrl, shotId, run]);

  return {
    isUpscaling,
    upscaleSuccess,
    handleUpscale,
    setActiveVariant,
    effectiveImageUrl: mediaUrl,
  };
};

import { useState, useCallback } from 'react';
import {
  createVideoEnhanceTask,
  type VideoEnhanceTaskParams,
} from '@/shared/lib/tasks/families/videoEnhance';
import type { VideoEnhanceSettings } from './useGenerationEditSettings';
import { useTaskPlaceholder } from '@/shared/hooks/tasks/useTaskPlaceholder';

export type { VideoEnhanceSettings } from './useGenerationEditSettings';

interface UseVideoEnhanceProps {
  projectId: string | undefined;
  videoUrl: string | undefined;
  shotId?: string;
  /** Generation ID to create variant on (for based_on relationship) */
  generationId?: string;
  /** Active variant ID - track which variant was enhanced */
  activeVariantId?: string | null;
  /** Settings from persistence system */
  settings: VideoEnhanceSettings;
  /** Setter for updating settings */
  updateSettings: (updates: Partial<VideoEnhanceSettings>) => void;
}

interface UseVideoEnhanceReturn {
  // Settings passed through for convenience
  settings: VideoEnhanceSettings;
  updateSetting: <K extends keyof VideoEnhanceSettings>(
    key: K,
    value: VideoEnhanceSettings[K]
  ) => void;

  // Validation
  isValid: boolean;
  canSubmit: boolean;

  // Actions
  handleGenerate: () => Promise<void>;

  // Status
  isGenerating: boolean;
  generateSuccess: boolean;
}

/**
 * Hook for managing video enhancement actions
 *
 * Settings are managed externally via the persistence system
 * This hook handles validation and task creation
 */
export function useVideoEnhance({
  projectId,
  videoUrl,
  shotId,
  generationId,
  activeVariantId,
  settings,
  updateSettings,
}: UseVideoEnhanceProps): UseVideoEnhanceReturn {
  const [isGenerating, setIsGenerating] = useState(false);
  const [generateSuccess, setGenerateSuccess] = useState(false);
  const run = useTaskPlaceholder();

  // Adapter to match the expected interface
  const updateSetting = useCallback(<K extends keyof VideoEnhanceSettings>(
    key: K,
    value: VideoEnhanceSettings[K]
  ) => {
    updateSettings({ [key]: value });
    // Reset success state when settings change
    setGenerateSuccess(false);
  }, [updateSettings]);

  // Validation: at least one mode must be enabled
  const isValid = settings.enableInterpolation || settings.enableUpscale;

  // Can submit: valid settings + required data
  const canSubmit = isValid && !!projectId && !!videoUrl && !isGenerating;

  // Handle generate action
  const handleGenerate = useCallback(async () => {
    if (!canSubmit || !projectId || !videoUrl) {
      return;
    }

    setIsGenerating(true);
    setGenerateSuccess(false);

    const enhanceLabel = [
      settings.enableInterpolation && 'Interpolation',
      settings.enableUpscale && 'Upscale',
    ].filter(Boolean).join(' + ');

    try {
      await run({
        taskType: 'video_enhance',
        label: enhanceLabel || 'Video Enhance',
        context: 'useVideoEnhance',
        toastTitle: 'Failed to create video enhancement task',
        create: () => {
          const params: VideoEnhanceTaskParams = {
            project_id: projectId,
            video_url: videoUrl,
            enable_interpolation: settings.enableInterpolation,
            enable_upscale: settings.enableUpscale,
            shot_id: shotId,
            based_on: generationId,
            source_variant_id: activeVariantId || undefined,
          };

          if (settings.enableInterpolation) {
            params.interpolation = {
              num_frames: settings.numFrames,
              use_calculated_fps: true,
            };
          }

          if (settings.enableUpscale) {
            params.upscale = {
              upscale_factor: settings.upscaleFactor,
              color_fix: settings.colorFix,
              output_quality: settings.outputQuality,
            };
          }

          return createVideoEnhanceTask(params);
        },
        onSuccess: () => {
          setGenerateSuccess(true);
        },
      });
    } finally {
      setIsGenerating(false);
    }
  }, [
    canSubmit,
    projectId,
    videoUrl,
    shotId,
    generationId,
    activeVariantId,
    settings,
    run,
  ]);

  return {
    settings,
    updateSetting,
    isValid,
    canSubmit,
    handleGenerate,
    isGenerating,
    generateSuccess,
  };
}

import { useState, useCallback } from 'react';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { uploadImageToStorage } from '@/shared/lib/media/imageUploader';
import { createImageInpaintTask } from '@/shared/lib/tasks/imageEditing/imageInpaint';
import { buildMaskedEditTaskParams } from '@/shared/lib/tasks/imageEditing/buildMaskedEditTaskParams';
import { generateMaskFromCanvas, createCanvasWithBackground } from '@/shared/lib/media/maskGeneration';
import type { ImageTransform } from './types';
import type { GenerationRow } from '@/domains/generation/types';
import type { EditAdvancedSettings, QwenEditModel } from '../useGenerationEditSettings';
import { convertToHiresFixApiParams } from '../useGenerationEditSettings';
import { getGenerationId } from '@/shared/lib/media/mediaTypeHelpers';
import { useTaskPlaceholder } from '@/shared/hooks/tasks/useTaskPlaceholder';

interface UseRepositionTaskCreationProps {
  media: GenerationRow;
  selectedProjectId: string | null;
  shotId?: string;
  toolTypeOverride?: string;
  imageDimensions: { width: number; height: number } | null;
  loras?: Array<{ url: string; strength: number }>;
  inpaintPrompt: string;
  inpaintNumGenerations: number;
  transform: ImageTransform;
  hasTransformChanges: boolean;
  createAsGeneration?: boolean;
  advancedSettings?: EditAdvancedSettings;
  activeVariantId?: string | null;
  qwenEditModel?: QwenEditModel;
  /** Function to create the transformed canvas */
  createTransformedCanvas: () => Promise<HTMLCanvasElement>;
}

interface UseRepositionTaskCreationReturn {
  isGeneratingReposition: boolean;
  repositionGenerateSuccess: boolean;
  handleGenerateReposition: () => Promise<void>;
}

/**
 * Hook for generating inpaint tasks from repositioned images.
 * Creates transformed image with mask for the dead space and submits to inpaint API.
 */
export function useRepositionTaskCreation({
  media,
  selectedProjectId,
  shotId,
  toolTypeOverride,
  imageDimensions,
  loras,
  inpaintPrompt,
  inpaintNumGenerations,
  transform: _transform,
  hasTransformChanges,
  createAsGeneration,
  advancedSettings,
  activeVariantId,
  qwenEditModel,
  createTransformedCanvas,
}: UseRepositionTaskCreationProps): UseRepositionTaskCreationReturn {
  const [isGeneratingReposition, setIsGeneratingReposition] = useState(false);
  const [repositionGenerateSuccess, setRepositionGenerateSuccess] = useState(false);
  const run = useTaskPlaceholder();

  // Generate transformed image and mask, then create inpaint task
  const handleGenerateReposition = useCallback(async () => {
    if (!selectedProjectId || !imageDimensions) {
      toast.error('Missing project or image dimensions');
      return;
    }

    if (!hasTransformChanges) {
      toast.error('Please move, scale, or rotate the image first');
      return;
    }

    setIsGeneratingReposition(true);

    try {
      await run({
        taskType: 'image_inpaint',
        label: inpaintPrompt.trim() || 'Fill edges...',
        context: 'useRepositionTaskCreation',
        toastTitle: 'Failed to create reposition task',
        create: async () => {
          const transformedCanvas = await createTransformedCanvas();

          // Generate mask from the transparent areas of the transformed image
          const maskCanvas = generateMaskFromCanvas(transformedCanvas, {
            alphaThreshold: 200,
            dilationPixels: 3,
          });

          // Create final image with green background to prevent anti-aliased edge artifacts
          const finalImageCanvas = createCanvasWithBackground(transformedCanvas, '#00FF00');

          // Convert canvases to blobs and upload
          const transformedBlob = await new Promise<Blob>((resolve, reject) => {
            finalImageCanvas.toBlob(blob => {
              if (blob) resolve(blob);
              else reject(new Error('Failed to create transformed image blob'));
            }, 'image/png');
          });

          const maskBlob = await new Promise<Blob>((resolve, reject) => {
            maskCanvas.toBlob(blob => {
              if (blob) resolve(blob);
              else reject(new Error('Failed to create mask blob'));
            }, 'image/png');
          });

          // Upload transformed image and mask
          const transformedFile = new File(
            [transformedBlob],
            `reposition_image_${media.id}_${Date.now()}.png`,
            { type: 'image/png' }
          );
          const maskFile = new File(
            [maskBlob],
            `reposition_mask_${media.id}_${Date.now()}.png`,
            { type: 'image/png' }
          );

          const [transformedUrl, maskUrl] = await Promise.all([
            uploadImageToStorage(transformedFile),
            uploadImageToStorage(maskFile)
          ]);

          // Create inpaint task with transformed image and mask
          const actualGenerationId = getGenerationId(media);
          const effectivePrompt = inpaintPrompt.trim() || 'seamlessly extend and fill the edges matching the existing image style and content';

          return createImageInpaintTask(
            buildMaskedEditTaskParams({
              projectId: selectedProjectId,
              imageUrl: transformedUrl,
              maskUrl,
              prompt: effectivePrompt,
              numGenerations: inpaintNumGenerations,
              generationId: actualGenerationId ?? undefined,
              shotId,
              toolType: toolTypeOverride,
              loras,
              createAsGeneration,
              sourceVariantId: activeVariantId || undefined,
              hiresFix: convertToHiresFixApiParams(advancedSettings),
              qwenEditModel,
            }),
          );
        },
        onSuccess: () => {
          setRepositionGenerateSuccess(true);
          setTimeout(() => {
            setRepositionGenerateSuccess(false);
          }, 1000);
        },
      });
    } finally {
      setIsGeneratingReposition(false);
    }
  }, [
    selectedProjectId,
    imageDimensions,
    hasTransformChanges,
    media,
    inpaintPrompt,
    inpaintNumGenerations,
    shotId,
    toolTypeOverride,
    loras,
    createTransformedCanvas,
    createAsGeneration,
    advancedSettings,
    activeVariantId,
    qwenEditModel,
    run,
  ]);

  return {
    isGeneratingReposition,
    repositionGenerateSuccess,
    handleGenerateReposition,
  };
}

import { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { GenerationRow } from '@/domains/generation/types';
import { createBatchZImageTurboImageToImageTasks } from '@/shared/lib/tasks/families/zImageTurboI2I';
import type { ActiveLora, FalLoraConfig, LoraModel } from '@/domains/lora/types/lora';
import type { LoraManagerState } from '@/domains/lora/types/loraManager';
import { useLoraManager } from '@/domains/lora/hooks/useLoraManager';
import { getGenerationId } from '@/shared/lib/media/mediaTypeHelpers';
import { useTaskPlaceholder } from '@/shared/hooks/tasks/useTaskPlaceholder';

interface Img2ImgPersistedState {
  strength: number;
  setStrength: (strength: number) => void;
  enablePromptExpansion: boolean;
  setEnablePromptExpansion: (enabled: boolean) => void;
  prompt: string;
  setPrompt: (prompt: string) => void;
  promptHasBeenSet: boolean;
  numGenerations: number;
}

interface Img2ImgSourceContext {
  baseImageUrl: string;
  activeVariantLocation?: string | null;
  activeVariantId?: string | null;
  shotId?: string;
}

interface Img2ImgTaskOptions {
  toolTypeOverride?: string;
  createAsGeneration?: boolean;
}

interface UseImg2ImgModeProps {
  media: GenerationRow;
  selectedProjectId: string | null;
  isVideo: boolean;
  availableLoras?: LoraModel[];
  state: Img2ImgPersistedState;
  source: Img2ImgSourceContext;
  options?: Img2ImgTaskOptions;
}

interface UseImg2ImgModeReturn {
  // State
  img2imgPrompt: string;
  img2imgStrength: number;
  enablePromptExpansion: boolean;
  isGeneratingImg2Img: boolean;
  img2imgGenerateSuccess: boolean;

  // Setters
  setImg2imgPrompt: (prompt: string) => void;
  setImg2imgStrength: (strength: number) => void;
  setEnablePromptExpansion: (enabled: boolean) => void;

  // LoRA Manager (full access)
  loraManager: LoraManagerState;

  // Actions
  handleGenerateImg2Img: () => Promise<void>;
}

/**
 * Hook for managing Img2Img mode state and generation
 * Uses Z Image Turbo I2I task type with full LoRA selector support
 * 
 * Strength, enablePromptExpansion, and prompt are persisted via editSettingsPersistence
 * Prompt is persisted per-generation (shared with other edit modes, never inherited)
 */
export const useImg2ImgMode = ({
  media,
  selectedProjectId,
  isVideo,
  availableLoras = [],
  state,
  source,
  options,
}: UseImg2ImgModeProps): UseImg2ImgModeReturn => {
  const {
    strength: img2imgStrength,
    setStrength: setImg2imgStrength,
    enablePromptExpansion,
    setEnablePromptExpansion,
    prompt: img2imgPrompt,
    setPrompt: setImg2imgPrompt,
    promptHasBeenSet: img2imgPromptHasBeenSet,
    numGenerations,
  } = state;
  const { baseImageUrl, activeVariantLocation, activeVariantId, shotId } = source;
  const { toolTypeOverride, createAsGeneration } = options ?? {};

  // Local state (not persisted)
  const [isGeneratingImg2Img, setIsGeneratingImg2Img] = useState(false);
  const [img2imgGenerateSuccess, setImg2imgGenerateSuccess] = useState(false);
  const run = useTaskPlaceholder();

  // Derive the base generation prompt from the generation params (best-effort)
  const baseGenerationPrompt = useMemo(() => {
    const params = media.params;
    const raw =
      (typeof params?.base_prompt === 'string' && params.base_prompt) ||
      (typeof params?.prompt === 'string' && params.prompt) ||
      '';
    return raw.trim();
  }, [media]);

  // Default Img2Img prompt to the prompt that generated the base image (one-time per generation)
  useEffect(() => {
    if (img2imgPromptHasBeenSet) return;
    if (img2imgPrompt && img2imgPrompt.trim().length > 0) return;
    if (!baseGenerationPrompt) return;

    setImg2imgPrompt(baseGenerationPrompt);
  }, [img2imgPromptHasBeenSet, img2imgPrompt, baseGenerationPrompt, setImg2imgPrompt]);

  // Use the shared LoRA manager hook
  const loraManager = useLoraManager(availableLoras, {
    projectId: selectedProjectId || undefined,
    persistenceScope: 'none', // Don't persist for img2img - it's a quick tool
    enableProjectPersistence: false,
    disableAutoLoad: true,
  });

  // Track generation to prevent double-submits
  const isSubmittingRef = useRef(false);

  const handleGenerateImg2Img = useCallback(async () => {
    // Validate inputs
    if (!selectedProjectId) {
      toast.error('No project selected');
      return;
    }

    if (isVideo) {
      toast.error('Img2Img is only available for images');
      return;
    }

    if (!baseImageUrl && !activeVariantLocation) {
      toast.error('No source image URL available');
      return;
    }

    // Prevent double-submits
    if (isSubmittingRef.current) {
      return;
    }

    isSubmittingRef.current = true;
    setIsGeneratingImg2Img(true);

    try {
      await run({
        taskType: 'z_image_turbo_i2i',
        label: img2imgPrompt.trim() || 'Img2Img...',
        context: 'useImg2ImgMode',
        toastTitle: 'Failed to create Img2Img tasks',
        create: () => {
          // Convert selected LoRAs to the format expected by the task
          const loras: FalLoraConfig[] = loraManager.selectedLoras.map((lora: ActiveLora) => ({
            path: lora.path,
            scale: lora.strength,
          }));

          // Use active variant's location if editing a variant, otherwise use the base image URL
          const effectiveImageUrl = activeVariantLocation || baseImageUrl;

          // Get actual generation ID (handle shot_generations case)
          const actualGenerationId = getGenerationId(media);

          return createBatchZImageTurboImageToImageTasks({
            project_id: selectedProjectId,
            image_url: effectiveImageUrl,
            prompt: img2imgPrompt.trim() || undefined,
            strength: img2imgStrength,
            enable_prompt_expansion: enablePromptExpansion,
            numImages: numGenerations,
            loras: loras.length > 0 ? loras : undefined,
            based_on: actualGenerationId ?? undefined,
            source_variant_id: activeVariantId || undefined,
            create_as_generation: createAsGeneration,
            tool_type: toolTypeOverride,
            shot_id: shotId,
          });
        },
        onSuccess: () => {
          setImg2imgGenerateSuccess(true);
          setTimeout(() => {
            setImg2imgGenerateSuccess(false);
          }, 2000);
        },
      });
    } finally {
      setIsGeneratingImg2Img(false);
      isSubmittingRef.current = false;
    }
  }, [
    selectedProjectId,
    isVideo,
    baseImageUrl,
    activeVariantLocation,
    activeVariantId,
    media,
    img2imgPrompt,
    img2imgStrength,
    enablePromptExpansion,
    numGenerations,
    loraManager.selectedLoras,
    createAsGeneration,
    toolTypeOverride,
    shotId,
    run,
  ]);

  return {
    // State
    img2imgPrompt,
    img2imgStrength,
    enablePromptExpansion,
    isGeneratingImg2Img,
    img2imgGenerateSuccess,

    // Setters
    setImg2imgPrompt,
    setImg2imgStrength,
    setEnablePromptExpansion,

    // LoRA Manager
    loraManager,

    // Actions
    handleGenerateImg2Img,
  };
};

