interface DefaultableFieldResult {
  isUsingDefault: boolean;
  displayValue: string;
}

export function getDefaultableField(
  localValue: string | undefined,
  defaultValue: string | undefined,
  hasDbOverride?: boolean
): DefaultableFieldResult {
  const isUsingDefault = localValue === undefined && (
    hasDbOverride !== undefined
      ? !hasDbOverride && defaultValue !== undefined
      : defaultValue !== undefined
  );

  return {
    isUsingDefault,
    displayValue: isUsingDefault ? (defaultValue ?? '') : (localValue ?? ''),
  };
}

export function detectGenerationMode(modelName?: string): 'i2v' | 'vace' {
  if (!modelName) return 'i2v';
  return modelName.toLowerCase().includes('vace') ? 'vace' : 'i2v';
}


export interface ShotBatchSettings {
  amountOfMotion?: number;
  motionMode?: 'basic' | 'advanced';
  selectedLoras?: LoraConfig[];
  phaseConfig?: PhaseConfig;
  prompt?: string;
  negativePrompt?: string;
  [key: string]: unknown;
}

type PhaseConfigRequest = Omit<PhaseConfig, 'mode'>;

// Strip mode field from phase config (backend determines mode from model)
export function stripModeFromPhaseConfig(config: PhaseConfig): PhaseConfigRequest {
  const { mode: _mode, ...rest } = config;
  return rest;
}

interface MotionTaskFieldsInput {
  amountOfMotion: number;
  motionMode: string;
  phaseConfig?: PhaseConfig;
  selectedPhasePresetId?: string | null;
  omitBasicPhaseConfig?: boolean;
}

export function buildMotionTaskFields({
  amountOfMotion,
  motionMode,
  phaseConfig,
  selectedPhasePresetId,
  omitBasicPhaseConfig = false,
}: MotionTaskFieldsInput): Record<string, unknown> {
  const shouldIncludePhaseConfig = !omitBasicPhaseConfig || motionMode !== 'basic' || !!selectedPhasePresetId;

  if (!phaseConfig) {
    return {};
  }

  return {
    amount_of_motion: amountOfMotion / 100,
    motion_mode: motionMode,
    phase_config: shouldIncludePhaseConfig ? stripModeFromPhaseConfig(phaseConfig) : undefined,
    selected_phase_preset_id: selectedPhasePresetId || undefined,
  };
}

export function buildTaskParams(
  settings: SegmentSettings,
  context: {
    projectId: string;
    shotId?: string;
    generationId?: string;
    childGenerationId?: string;
    segmentIndex: number;
    startImageUrl: string;
    endImageUrl?: string; // Optional for trailing segments (single-image-to-video)
    startImageGenerationId?: string;
    endImageGenerationId?: string;
    pairShotGenerationId?: string;
    startImageVariantId?: string;
    endImageVariantId?: string;
    projectResolution?: string;
    modelName?: string;
    modelType?: 'i2v' | 'vace';
    continuationConfig?: ContinuationConfig;
    frameOverlapFromPrevious?: number;
    // Optional enhanced prompt (AI-enhanced version, kept separate from base_prompt)
    enhancedPrompt?: string;
    // Canonical travel guidance input for this segment.
    travelGuidance?: TravelGuidance;
  }
): IndividualTravelSegmentParams {
  const motionFields = buildMotionTaskFields({
    amountOfMotion: settings.amountOfMotion,
    motionMode: settings.motionMode,
    phaseConfig: settings.phaseConfig ?? DEFAULT_PHASE_CONFIG,
    selectedPhasePresetId: settings.selectedPhasePresetId,
    omitBasicPhaseConfig: true,
  });

  // Detect trailing segment: no end image means single-image-to-video (last segment)
  const isTrailingSegment = !context.endImageUrl;

  return {
    project_id: context.projectId,
    shot_id: context.shotId,
    parent_generation_id: context.generationId,
    child_generation_id: context.childGenerationId,
    segment_index: context.segmentIndex,
    start_image_url: context.startImageUrl,
    end_image_url: context.endImageUrl,
    // For trailing segments (no end image), mark as last segment so worker uses I2V mode
    is_last_segment: isTrailingSegment,
    start_image_generation_id: context.startImageGenerationId,
    end_image_generation_id: context.endImageGenerationId,
    pair_shot_generation_id: context.pairShotGenerationId,
    start_image_variant_id: context.startImageVariantId,
    end_image_variant_id: context.endImageVariantId,
    // Settings
    base_prompt: settings.prompt,
    negative_prompt: settings.negativePrompt,
    // Enhanced prompt (AI-enhanced version) - worker should prefer this over base_prompt when present
    ...(context.enhancedPrompt && { enhanced_prompt: context.enhancedPrompt }),
    num_frames: settings.numFrames,
    random_seed: settings.randomSeed,
    seed: settings.seed,
    ...motionFields,
    loras: settings.loras.map(l => ({ path: l.path, strength: l.strength })),
    ...(settings.inferenceSteps !== undefined && { num_inference_steps: settings.inferenceSteps }),
    ...(settings.guidanceScale !== undefined && { guidance_scale: settings.guidanceScale }),
    make_primary_variant: settings.makePrimaryVariant,
    // Resolution
    ...(context.projectResolution && { parsed_resolution_wh: context.projectResolution }),
    ...(context.modelName && { model_name: context.modelName }),
    ...(context.modelType && { model_type: context.modelType }),
    ...(context.continuationConfig && { continuation_config: context.continuationConfig }),
    ...(context.frameOverlapFromPrevious !== undefined ? { frame_overlap_from_previous: context.frameOverlapFromPrevious } : {}),
    ...(context.travelGuidance && { travel_guidance: context.travelGuidance }),
  };
}

import { resolveSeed32Bit } from '../taskCreation';
import { buildBasicModePhaseConfig } from '@/shared/types/phaseConfig';
import { resolveTravelGuidanceState } from './travelGuidance';
import {
  buildTaskPayloadSnapshot,
} from './taskPayloadSnapshot';
import { readTravelContractData } from './travelContractData';
import {
  asNumber,
  asString,
  resolveNumberCandidate,
  resolveStringCandidate,
  toRecordOrEmpty,
  type UnknownRecord
} from './taskParamParsers';
import { asMotionMode, asPhaseConfig } from './segmentTypeCoercers';
import type {
  IndividualTravelSegmentParams,
  SegmentBuildState,
} from './families/individualTravelSegment/types';
import type { StructureVideoConfig } from './travelBetweenImages/taskTypes';

export const MAX_SEGMENT_FRAMES = 81;
const DEFAULT_I2V_MODEL = 'wan_2_2_i2v_lightning_baseline_2_2_2';

function sanitizeStructureVideosFromGuidance(
  structureGuidance: UnknownRecord | undefined,
): StructureVideoConfig[] | undefined {
  if (!Array.isArray(structureGuidance?.videos)) {
    return undefined;
  }

  const structureVideos = structureGuidance.videos
    .map((video) => {
      if (!video || typeof video !== 'object' || Array.isArray(video)) {
        return null;
      }

      const record = video as Record<string, unknown>;
      if (typeof record.path !== 'string') {
        return null;
      }

      return {
        path: record.path,
        start_frame: typeof record.start_frame === 'number' ? record.start_frame : 0,
        end_frame: typeof record.end_frame === 'number' ? record.end_frame : 0,
        treatment: record.treatment === 'clip' ? 'clip' : 'adjust',
        ...(typeof record.source_start_frame === 'number'
          ? { source_start_frame: record.source_start_frame }
          : {}),
        ...(record.source_end_frame === null || typeof record.source_end_frame === 'number'
          ? { source_end_frame: record.source_end_frame ?? null }
          : {}),
      } satisfies StructureVideoConfig;
    })
    .filter((video): video is StructureVideoConfig => video !== null);

  return structureVideos.length > 0 ? structureVideos : undefined;
}

function buildInputImages(params: IndividualTravelSegmentParams): string[] {
  return params.end_image_url
    ? [params.start_image_url, params.end_image_url]
    : [params.start_image_url];
}

function resolveFinalSeed(
  params: IndividualTravelSegmentParams,
  orig: UnknownRecord,
  orchDetails: UnknownRecord,
): number {
  const baseSeed = asNumber(orig.seed_to_use)
    ?? asNumber(orig.seed)
    ?? asNumber(orchDetails.seed_base)
    ?? 789;

  return resolveSeed32Bit({
    seed: params.seed,
    randomize: params.random_seed === true,
    fallbackSeed: baseSeed,
    field: 'seed',
  });
}

function mergeAdditionalLoraMap(
  target: Record<string, number>,
  source: unknown,
): void {
  const sourceRecord = toRecordOrEmpty(source);
  for (const [path, strength] of Object.entries(sourceRecord)) {
    if (typeof strength === 'number') {
      target[path] = strength;
    }
  }
}

function buildAdditionalLoras(
  params: IndividualTravelSegmentParams,
  orig: UnknownRecord,
  orchDetails: UnknownRecord,
  contractAdditionalLoras?: UnknownRecord,
): Record<string, number> {
  const additionalLoras: Record<string, number> = {};

  if (params.loras !== undefined) {
    for (const lora of params.loras) {
      additionalLoras[lora.path] = lora.strength;
    }
    return additionalLoras;
  }

  if (contractAdditionalLoras) {
    mergeAdditionalLoraMap(additionalLoras, contractAdditionalLoras);
  }
  mergeAdditionalLoraMap(additionalLoras, orig.additional_loras);
  if (Object.keys(additionalLoras).length === 0) {
    mergeAdditionalLoraMap(additionalLoras, orchDetails.additional_loras);
  }
  return additionalLoras;
}

function resolveStructureGuidance(
  params: IndividualTravelSegmentParams,
  orig: UnknownRecord,
  orchDetails: UnknownRecord,
  contractModelName?: string,
  contractTravelGuidance?: UnknownRecord,
  contractStructureGuidance?: UnknownRecord,
): { travelGuidance?: import('./travelBetweenImages/taskTypes').TravelGuidance; structureGuidance?: UnknownRecord; structureVideos?: StructureVideoConfig[] } {
  const modelName = resolveStringCandidate(
    contractModelName,
    asString(params.originalParams && (params.originalParams as Record<string, unknown>).model_name),
    asString(orig.model_name),
    asString(orchDetails.model_name),
  );
  const resolved = resolveTravelGuidanceState({
    modelName,
    travelGuidance: params.travel_guidance ?? contractTravelGuidance ?? orig.travel_guidance ?? orchDetails.travel_guidance,
    structureGuidance: params.structure_guidance ?? contractStructureGuidance ?? orig.structure_guidance ?? orchDetails.structure_guidance,
    structureVideos: params.structure_videos ?? orchDetails.structure_videos ?? orig.structure_videos,
    defaultVideoTreatment: 'adjust',
    defaultUni3cEndPercent: 0.1,
  });

  return {
    travelGuidance: resolved.travelGuidance,
    structureGuidance: resolved.structureGuidance,
    structureVideos: resolved.structureVideos.length > 0 ? resolved.structureVideos : undefined,
  };
}

export function buildSegmentState(params: IndividualTravelSegmentParams): SegmentBuildState {
  const snapshot = buildTaskPayloadSnapshot(params.originalParams);
  const contractData = readTravelContractData(snapshot);
  const orig = snapshot.rawParams;
  const orchDetails = snapshot.orchestratorDetails;
  const inputImages = buildInputImages(params);
  const allInputImages = contractData.inputImages ?? inputImages;
  const finalSeed = resolveFinalSeed(params, orig, orchDetails);
  const additionalLoras = buildAdditionalLoras(params, orig, orchDetails, contractData.additionalLoras);
  const motionMode = (
    params.motion_mode
    ?? asMotionMode(contractData.motionMode)
    ?? 'basic'
  );
  const amountOfMotion = params.amount_of_motion
    ?? contractData.amountOfMotion
    ?? 0.5;
  const explicitPhaseConfig = (
    params.phase_config
    ?? asPhaseConfig(contractData.phaseConfig)
  );
  const phaseConfig = explicitPhaseConfig
    ?? buildBasicModePhaseConfig(false, amountOfMotion, params.loras ?? []);
  const advancedMode = motionMode === 'basic'
    ? false
    : (
      params.advanced_mode
      ?? contractData.advancedMode
      ?? !!explicitPhaseConfig
    );
  const loraMultipliers = phaseConfig.phases.flatMap((phase) =>
    (phase.loras || []).map((lora) => ({
      url: lora.url,
      multiplier: typeof lora.multiplier === 'number' ? lora.multiplier : Number(lora.multiplier) || 0,
    })),
  );
  const modelName = asString(params.model_name)
    ?? contractData.modelName
    ?? DEFAULT_I2V_MODEL;
  const flowShift = resolveNumberCandidate(
    phaseConfig.flow_shift,
    orig.flow_shift,
    orchDetails.flow_shift,
  ) ?? 5;
  const sampleSolver = resolveStringCandidate(
    phaseConfig.sample_solver,
    orig.sample_solver,
    orchDetails.sample_solver,
  ) ?? 'euler';
  const guidanceScale = resolveNumberCandidate(
    params.guidance_scale,
    phaseConfig.phases?.[0]?.guidance_scale,
    orig.guidance_scale,
    orchDetails.guidance_scale,
  ) ?? 1;
  const guidance2Scale = resolveNumberCandidate(
    phaseConfig.phases?.[1]?.guidance_scale,
    orig.guidance2_scale,
    orchDetails.guidance2_scale,
  ) ?? 1;
  const guidancePhases = resolveNumberCandidate(
    phaseConfig.num_phases,
    orig.guidance_phases,
    orchDetails.guidance_phases,
  ) ?? 2;
  const numInferenceSteps = params.num_inference_steps
    ?? (phaseConfig.steps_per_phase
      ? phaseConfig.steps_per_phase.reduce((sum: number, steps: number) => sum + steps, 0)
      : (
        resolveNumberCandidate(orig.num_inference_steps, orchDetails.num_inference_steps)
        ?? 6
      ));
  const modelSwitchPhase = resolveNumberCandidate(
    phaseConfig.model_switch_phase,
    orig.model_switch_phase,
    orchDetails.model_switch_phase,
  ) ?? 1;
  const switchThreshold = orig.switch_threshold ?? orchDetails.switch_threshold;
  const rawNumFrames = resolveNumberCandidate(params.num_frames, orig.num_frames) ?? 49;
  const numFrames = Math.min(rawNumFrames, MAX_SEGMENT_FRAMES);
  const basePrompt = resolveStringCandidate(
    params.base_prompt,
    contractData.prompt,
    orig.base_prompt,
    orig.prompt,
  ) ?? '';
  const negativePrompt = resolveStringCandidate(
    params.negative_prompt,
    contractData.negativePrompt,
  ) ?? '';
  const enhancedPrompt = resolveStringCandidate(
    params.enhanced_prompt,
    contractData.enhancedPrompt,
  );
  const fpsHelpers = resolveNumberCandidate(orig.fps_helpers, orchDetails.fps_helpers) ?? 16;
  const segmentFramesExpanded = contractData.segmentFramesExpanded;
  const frameOverlapExpanded = contractData.frameOverlapExpanded;
  const continuationConfig = (
    params.continuation_config
    ?? (contractData.continuationConfig as import('./travelBetweenImages/taskTypes').ContinuationConfig | undefined)
  );
  const structureState = resolveStructureGuidance(
    params,
    orig,
    orchDetails,
    contractData.modelName,
    contractData.travelGuidance,
    contractData.structureGuidance,
  );
  const structureGuidance = structureState.structureGuidance;
  const structureVideos = structureState.structureVideos
    ?? sanitizeStructureVideosFromGuidance(structureGuidance);

  return {
    orig,
    orchDetails,
    inputImages,
    allInputImages,
    finalSeed,
    additionalLoras,
    motionMode,
    amountOfMotion,
    phaseConfig,
    advancedMode,
    loraMultipliers,
    modelName,
    flowShift,
    sampleSolver,
    guidanceScale,
    guidance2Scale,
    guidancePhases,
    numInferenceSteps,
    modelSwitchPhase,
    switchThreshold,
    numFrames,
    basePrompt,
    negativePrompt,
    enhancedPrompt,
    fpsHelpers,
    segmentFramesExpanded,
    frameOverlapExpanded,
    continuationConfig,
    travelGuidance: structureState.travelGuidance,
    structureGuidance,
    structureVideos,
  };
}

