import { ValidationError } from '@/shared/lib/errorHandling/errors';
import type { TaskParams, TaskType } from '@/types/database';

export const DEFAULT_ASPECT_RATIO = '1:1';

export interface ProjectResolutionResult {
  resolution: string;
  aspectRatio: string;
}

export interface RawTaskCreationRequest {
  project_id: string;
  task_type: TaskType;
  params: TaskParams;
}

export interface FamilyTaskCreationRequest {
  project_id: string;
  family: string;
  input: Record<string, unknown>;
}

export type TaskCreationRequest = RawTaskCreationRequest | FamilyTaskCreationRequest;
export type BaseTaskParams = TaskCreationRequest;

/**
 * Successful task-creation response shape.
 * `task_ids` is present for batched responses. `task_id` remains populated
 * with the first id so existing single-task call sites keep working.
 */
export interface TaskCreationResult {
  task_id: string;
  task_ids?: string[];
  status: string;
  meta?: Record<string, unknown>;
}

export class TaskValidationError extends ValidationError {
  constructor(message: string, field?: string) {
    super(message, { field });
    this.name = 'TaskValidationError';
  }
}

/**
 * Hires fix API parameters for image generation/edit tasks.
 * Uses snake_case to match API directly.
 */
export interface HiresFixApiParams {
  /** Number of inference steps (used for single-pass or base pass in two-pass mode) */
  num_inference_steps?: number;
  hires_scale?: number;
  hires_steps?: number;
  hires_denoise?: number;
  /** Lightning LoRA strength for phase 1 (initial generation) */
  lightning_lora_strength_phase_1?: number;
  /** Lightning LoRA strength for phase 2 (hires/refinement pass) */
  lightning_lora_strength_phase_2?: number;
  additional_loras?: Record<string, string>;
}

import { getSupabasePublishableKey, getSupabaseUrl } from '@/integrations/supabase/config/env';
import { isAbortError } from '@/shared/lib/errorHandling/errorUtils';
import { normalizeAndPresentAndRethrow } from '@/shared/lib/errorHandling/runtimeError';
import { AuthError, NetworkError, ServerError } from '@/shared/lib/errorHandling/errors';
import { readAccessTokenFromStorage } from '@/shared/lib/supabaseSession';
import { generateUUID } from './ids';
import { parseTaskCreationResponse } from './parseTaskCreationResponse';
import type { BaseTaskParams, TaskCreationResult } from './types';

function isFamilyTaskRequest(taskParams: BaseTaskParams): taskParams is Extract<BaseTaskParams, { family: string }> {
  return 'family' in taskParams;
}

/**
 * Creates a task using the unified create-task edge function.
 */
export async function createTask(taskParams: BaseTaskParams): Promise<TaskCreationResult> {
  // Read access token from localStorage — avoids navigator.locks contention.
  // getSession() acquires a shared navigator.lock blocked during token refresh.
  const accessToken = readAccessTokenFromStorage();

  if (!accessToken) {
    throw new AuthError('Please log in to create tasks', { needsLogin: true });
  }

  const startTime = Date.now();
  const requestId = `${startTime}-${Math.random().toString(36).slice(2, 8)}`;
  const taskIdentifier = isFamilyTaskRequest(taskParams)
    ? taskParams.family
    : taskParams.task_type;
  const requestContext = {
    requestId,
    taskType: taskIdentifier,
    projectId: taskParams.project_id,
  };
  const timeoutMs = 20000; // 20s safety timeout to avoid indefinite UI stall
  const controller = new AbortController();
  const timeout = setTimeout(() => {
    controller.abort();
  }, timeoutMs);

  try {
    // Generate an idempotency key to prevent duplicate task creation from
    // network retries or double-clicks. The server will return the existing
    // task if this key was already used.
    const idempotency_key = generateUUID();

    const response = await fetch(`${getSupabaseUrl()}/functions/v1/create-task`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${accessToken}`,
        apikey: getSupabasePublishableKey(),
      },
      body: JSON.stringify({
        ...(isFamilyTaskRequest(taskParams)
          ? {
              family: taskParams.family,
              project_id: taskParams.project_id,
              input: taskParams.input,
            }
          : {
              params: taskParams.params,
              task_type: taskParams.task_type,
              project_id: taskParams.project_id,
              dependant_on: null,
            }),
        idempotency_key,
      }),
      signal: controller.signal,
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => '');
      throw new ServerError(errorText || 'Failed to create task', {
        context: requestContext,
      });
    }

    const data = await response.json() as unknown;
    return parseTaskCreationResponse(data, requestContext);
  } catch (err: unknown) {
    const context = {
      requestId,
      taskType: taskIdentifier,
      projectId: taskParams.project_id,
      durationMs: Date.now() - startTime,
    };

    if (import.meta.env.DEV) {
      console.error('[createTask] invoke FAILED', context, err);
    }

    // Normalize abort errors for better UX
    if (isAbortError(err)) {
      throw new NetworkError('Task creation timed out. Please try again.', {
        isTimeout: true,
        context,
        cause: err instanceof Error ? err : undefined,
      });
    }

    normalizeAndPresentAndRethrow(err, {
      context: 'TaskCreation',
      showToast: false,
      logData: context,
    });
  } finally {
    clearTimeout(timeout);
  }
}

